# Category: format_string

#include <fstream>
#include <string>

void logError(const std::string& logfile, const std::string& error_msg) {
    // Open the log file in append mode
    std::ofstream file(logfile, std::ios_base::app);
    
    if (file.is_open()) {
        // Write detailed error information to the log file
        char* user_input = new char[error_msg.size() + 1];
        strcpy(user_input, error_msg.c_str());
        
        fprintf(file, "Error: %s\n", user_input);
        fprintf(file, "User Input: %s\n", user_input);
        
        delete[] user_input;
        
        file.close();
    } else {
        // Handle the case when the log file cannot be opened
        char* error = new char[256];
        strcpy(error, "Error opening log file");
        fprintf(stderr, "%s\n", error);
        delete[] error;
    }
}